  1→import React, { useState, useEffect } from 'react';
  2→import { createPortal } from 'react-dom';
  3→import { User } from '../types';
  4→import {
  5→  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  6→  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  7→  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight,
  8→  Palette, Eye, Globe, Lock
  9→} from 'lucide-react';
 10→import jsPDF from 'jspdf';
 11→import StripeCheckout from '../components/StripeCheckout';
 12→
 13→interface AccountProps {
 14→  user: User | null;
 15→  onLogout: () => void;
 16→  onNavigate: (view: any) => void;
 17→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 18→  projectCount: number;
 19→  maxProjects: number;
 20→  initialTab?: 'profile' | 'subscription' | 'billing' | 'whitelabel';
 21→}
 22→
 23→const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
 24→  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing' | 'whitelabel'>(initialTab);
 25→  const [apiKeyCopied, setApiKeyCopied] = useState(false);
 26→  const [isProcessing, setIsProcessing] = useState(false);
 27→  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
 28→  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
 29→  const [paidAmount, setPaidAmount] = useState(0);
 30→  const [paymentHistory, setPaymentHistory] = useState([
 31→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 32→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 33→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 34→  ]);
 35→
 36→  // White Label state
 37→  const [whiteLabel, setWhiteLabel] = useState(() => {
 38→    try {
 39→      const saved = localStorage.getItem('citedby-whitelabel');
 40→      return saved ? JSON.parse(saved) : { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' };
 41→    } catch { return { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' }; }
 42→  });
 43→  const [wlSaved, setWlSaved] = useState(false);
 44→
 45→  const handleSaveWhiteLabel = () => {
 46→    localStorage.setItem('citedby-whitelabel', JSON.stringify(whiteLabel));
 47→    setWlSaved(true);
 48→    setTimeout(() => setWlSaved(false), 2000);
 49→  };
 50→
 51→  const generateBrandedPdf = () => {
 52→    const doc = new jsPDF();
 53→    doc.setFillColor(whiteLabel.primaryColor || '#a855f7');
 54→    doc.rect(0, 0, 210, 40, 'F');
 55→    doc.setTextColor(255, 255, 255);
 56→    doc.setFontSize(22);
 57→    doc.setFont('helvetica', 'bold');
 58→    doc.text(whiteLabel.agencyName || 'Mon Agence', 20, 25);
 59→    doc.setFontSize(10);
 60→    doc.text('Rapport AEO — Marque Blanche', 20, 33);
 61→    doc.setTextColor(60, 60, 60);
 62→    doc.setFontSize(12);
 63→    doc.text('Rapport de Visibilité IA', 20, 55);
 64→    doc.setFontSize(10);
 65→    doc.setFont('helvetica', 'normal');
 66→    doc.text(`Généré le ${new Date().toLocaleDateString('fr-FR')}`, 20, 63);
 67→    doc.text(`Client : ${user?.name || 'N/A'}`, 20, 70);
 68→    doc.setFontSize(14);
 69→    doc.setFont('helvetica', 'bold');
 70→    doc.text('Score Global AEO', 20, 90);
 71→    doc.setFontSize(36);
 72→    doc.setTextColor(whiteLabel.primaryColor || '#a855f7');
 73→    doc.text('78/100', 20, 110);
 74→    doc.setTextColor(100, 100, 100);
 75→    doc.setFontSize(9);
 76→    doc.text(`Powered by ${whiteLabel.agencyName || 'CitedBy.ai'}`, 20, 280);
 77→    doc.save(`Rapport_${whiteLabel.agencyName || 'AEO'}_${Date.now()}.pdf`);
 78→  };
 79→
 80→  useEffect(() => {
 81→    setActiveTab(initialTab);
 82→  }, [initialTab]);
 83→
 84→  useEffect(() => {
 85→    if (upgradeModal && paymentStep === 'success') { document.body.style.overflow = 'hidden'; }
 86→    return () => { document.body.style.overflow = ''; };
 87→  }, [upgradeModal, paymentStep]);
 88→
 89→  if (!user) return null;
 90→
 91→  // ── Helpers ──
 92→
 93→  const handleCopyApiKey = () => {
 94→    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
 95→    setApiKeyCopied(true);
 96→    setTimeout(() => setApiKeyCopied(false), 2000);
 97→  };
 98→
 99→  const getPlanDetails = (plan: string) => {
100→    switch (plan) {
101→      case 'enterprise':
102→        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
103→      case 'pro':
104→        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
105→      default:
106→        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
107→    }
108→  };
109→
110→  const planDetails = getPlanDetails(user.plan);
111→  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
112→  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;
113→
114→  // ── Pricing data ──
115→
116→  const plans = [
117→    {
118→      id: 'free', name: 'Starter', price: 29, period: '/mois',
119→      icon: <Droplet size={24} />, current: user.plan === 'free',
120→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
121→      cta: 'Plan Actuel',
122→    },
123→    {
124→      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
125→      icon: <Fuel size={24} />, current: user.plan === 'pro',
126→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
127→      cta: 'Passer Pro',
128→    },
129→    {
130→      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
131→      icon: <Database size={24} />, current: user.plan === 'enterprise',
132→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
133→      cta: 'Passer Agency',
134→    },
135→  ];
136→
137→  // Prix du plan actuel de l'utilisateur
138→  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;
139→
140→  const handleUpgradeClick = (planId: string) => {
141→    const targetPlan = plans.find(p => p.id === planId);
142→    if (!targetPlan || targetPlan.current) return;
143→    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
144→    setPaymentStep('payment');
145→  };
146→
147→  const handleProcessPayment = () => {
148→    if (!upgradeModal) return;
149→    setIsProcessing(true);
150→    setTimeout(() => {
151→      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
152→      const now = new Date();
153→      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
154→      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
155→      const newInvoice = {
156→        id: invoiceNum,
157→        date: dateStr,
158→        amount: amountPaid,
159→        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
160→        status: 'Payé',
161→      };
162→      setPaymentHistory(prev => [newInvoice, ...prev]);
163→      setPaidAmount(amountPaid);
164→      onUpgrade(upgradeModal.planId as any);
165→      setIsProcessing(false);
166→      setPaymentStep('success');
167→    }, 2500);
168→  };
169→
170→  const handleCloseUpgradeModal = () => {
171→    setUpgradeModal(null);
172→    setPaymentStep('recap');
173→    setPaidAmount(0);
174→  };
175→
176→  // ── Invoice PDF ──
177→
178→  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
179→    const doc = new jsPDF();
180→    doc.setFontSize(22);
181→    doc.setFont('helvetica', 'bold');
182→    doc.text('CitedBy.ai', 20, 20);
183→    doc.setFontSize(10);
184→    doc.setFont('helvetica', 'normal');
185→    doc.text(`Facture N° ${payment.id}`, 20, 30);
186→    doc.text(`Date : ${payment.date}`, 20, 35);
187→    doc.text('Facturé à :', 140, 30);
188→    doc.setFont('helvetica', 'bold');
189→    doc.text(user.name || 'Client', 140, 35);
190→    doc.setFont('helvetica', 'normal');
191→    doc.text(user.email || '', 140, 40);
192→    doc.line(20, 55, 190, 55);
193→    doc.setFont('helvetica', 'bold');
194→    doc.text('Description', 20, 62);
195→    doc.text('Montant HT', 160, 62);
196→    doc.line(20, 66, 190, 66);
197→    const priceHT = (payment.amount / 1.2).toFixed(2);
198→    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
199→    doc.setFont('helvetica', 'normal');
200→    doc.text(payment.desc, 20, 75);
201→    doc.text(`${priceHT} €`, 160, 75);
202→    doc.line(20, 90, 190, 90);
203→    doc.text('Sous-total HT :', 130, 100);
204→    doc.text(`${priceHT} €`, 160, 100);
205→    doc.text('TVA (20%) :', 130, 107);
206→    doc.text(`${tva} €`, 160, 107);
207→    doc.setFont('helvetica', 'bold');
208→    doc.setFontSize(12);
209→    doc.text('Total TTC :', 130, 117);
210→    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
211→    doc.setFontSize(8);
212→    doc.setFont('helvetica', 'italic');
213→    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
214→    doc.save(`Facture_${payment.id}.pdf`);
215→  };
216→
217→  // ── Render ──
218→
219→  return (
220→    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
221→
222→      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
223→      {upgradeModal && paymentStep === 'payment' && (
224→        <div className="animate-in fade-in slide-in-from-right duration-500">
225→          <StripeCheckout
226→            mode="subscription"
227→            productName={`Plan ${upgradeModal.planName}`}
228→            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
229→            amount={upgradeModal.newPrice - currentPlanPrice}
230→            amountDetails={[
231→              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
232→              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
233→              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
234→            ]}
235→            userEmail={user.email}
236→            onConfirm={handleProcessPayment}
237→            onBack={() => setPaymentStep('recap')}
238→            isProcessing={isProcessing}
239→          />
240→        </div>
241→      )}
242→
243→      {/* Contenu principal — masqué pendant le paiement */}
244→      {!(upgradeModal && paymentStep === 'payment') && (<>
245→
246→      {/* Header */}
247→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
248→        <div className="flex items-center gap-4">
249→          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
250→            {user.name.charAt(0).toUpperCase()}
251→          </div>
252→          <div>
253→            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
254→            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
255→          </div>
256→        </div>
257→        <button
258→          onClick={onLogout}
259→          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
260→        >
261→          <LogOut size={16} /> Déconnexion
262→        </button>
263→      </div>
264→
265→      {/* Tabs */}
266→      <div className="flex justify-center mb-10">
267→        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
268→          {([
269→            { key: 'profile', icon: UserIcon, label: 'Profil' },
270→            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
271→            { key: 'billing', icon: CreditCard, label: 'Facturation' },
272→            ...(user.plan === 'enterprise' ? [{ key: 'whitelabel' as const, icon: Palette, label: 'White Label' }] : []),
273→          ] as const).map(tab => (
274→            <button
275→              key={tab.key}
276→              onClick={() => setActiveTab(tab.key)}
277→              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
278→                activeTab === tab.key
279→                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
280→                  : 'text-gray-500 hover:text-white'
281→              }`}
282→            >
283→              <tab.icon size={16} /> {tab.label}
284→            </button>
285→          ))}
286→        </div>
287→      </div>
288→
289→      {/* ═══════════════════════════════════════════════
290→          TAB 1 : PROFIL
291→          ═══════════════════════════════════════════════ */}
292→      {activeTab === 'profile' && (
293→        <div className="animate-in fade-in duration-300 grid lg:grid-cols-3 gap-8">
294→
295→          {/* Left: Profile Card + GTO Balance */}
296→          <div className="space-y-6">
297→            {/* Profile summary */}
298→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
299→              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
300→              <div className="relative">
301→                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-purple-500 to-violet-600 rounded-full flex items-center justify-center text-white font-bold text-4xl shadow-xl shadow-purple-500/20 mb-4 border-4 border-black">
302→                  {user.name.charAt(0).toUpperCase()}
303→                </div>
304→                <h2 className="text-xl font-bold text-white">{user.name}</h2>
305→                <p className="text-sm text-gray-500 mb-4">{user.email}</p>
306→                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide ${planDetails.style}`}>
307→                  {planDetails.icon}
308→                  {planDetails.marketingName}
309→                </div>
310→              </div>
311→            </div>
312→
313→            {/* GTO Gas balance */}
314→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
315→              <div className="flex justify-between items-start mb-4">
316→                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
317→                  <Fuel size={24} />
318→                </div>
319→                <button
320→                  onClick={() => onNavigate('recharge')}
321→                  className="text-xs bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold px-3 py-1.5 rounded-full hover:brightness-110 transition-all"
322→                >
323→                  Recharger
324→                </button>
325→              </div>
326→              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
327→              <div className="text-4xl font-bold text-white mb-2">{user.credits}</div>
328→              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
329→                <div className="bg-purple-500 h-full rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
330→              </div>
331→              <p className="text-xs text-gray-500 mt-2">~{Math.floor(user.credits / 10)} audits restants</p>
332→            </div>
333→          </div>
334→
335→          {/* Right: Settings */}
336→          <div className="lg:col-span-2 space-y-8">
337→            {/* API Keys */}
338→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
339→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
340→                <Key size={20} className="text-purple-400" /> Clés API & Intégrations
341→              </h3>
342→              <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
343→                <div className="flex-1 overflow-hidden">
344→                  <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
345→                  <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0, 8)}...</code>
346→                </div>
347→                <button
348→                  onClick={handleCopyApiKey}
349→                  className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-500 hover:text-white"
350→                  title="Copier la clé"
351→                >
352→                  {apiKeyCopied ? <Check size={18} className="text-purple-400" /> : <Copy size={18} />}
353→                </button>
354→              </div>
355→              <p className="text-xs text-gray-500 mt-3">
356→                Cette clé permet d'utiliser l'API CitedBy.ai. Ne la partagez jamais.
357→              </p>
358→              <button
359→                onClick={() => onNavigate('api-developer')}
360→                className="mt-4 text-sm text-purple-400 hover:text-purple-300 transition-colors flex items-center gap-1.5 font-medium"
361→              >
362→                <ArrowUpRight size={14} /> Documentation API complète
363→              </button>
364→            </div>
365→
366→            {/* Personal Info */}
367→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
368→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
369→                <UserIcon size={20} className="text-blue-400" /> Informations Personnelles
370→              </h3>
371→              <div className="grid md:grid-cols-2 gap-6">
372→                <div className="space-y-2">
373→                  <label className="text-sm font-medium text-gray-500">Nom Complet</label>
374→                  <input type="text" defaultValue={user.name} className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
375→                </div>
376→                <div className="space-y-2">
377→                  <label className="text-sm font-medium text-gray-500">Email</label>
378→                  <input type="email" defaultValue={user.email} disabled className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-gray-500 cursor-not-allowed" />
379→                </div>
380→                <div className="space-y-2 md:col-span-2">
381→                  <label className="text-sm font-medium text-gray-500">Workspace / Entreprise</label>
382→                  <input type="text" defaultValue="Mon Espace Personnel" className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
383→                </div>
384→              </div>
385→              <div className="mt-6 flex justify-end">
386→                <button className="btn-gradient px-6 py-2.5 text-white font-bold text-sm">Enregistrer les modifications</button>
387→              </div>
388→            </div>
389→
390→            {/* Notifications */}
391→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
392→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
393→                <Bell size={20} className="text-purple-400" /> Préférences de notification
394→              </h3>
395→              <div className="space-y-4">
396→                {[
397→                  { label: "Rapport d'audit terminé", desc: 'Recevoir un email quand une analyse est finie.', default: true },
398→                  { label: 'Alerte de baisse de score', desc: 'Notification si le score AEO chute de plus de 10%.', default: true },
399→                  { label: 'Offres & Nouveautés', desc: 'Newsletters produit et mises à jour.', default: false },
400→                ].map((pref, i) => (
401→                  <div key={i} className="flex items-start justify-between pb-4 border-b border-white/[0.06] last:border-0 last:pb-0">
402→                    <div>
403→                      <p className="text-sm font-medium text-white">{pref.label}</p>
404→                      <p className="text-xs text-gray-500 mt-0.5">{pref.desc}</p>
405→                    </div>
406→                    <label className="relative inline-flex items-center cursor-pointer">
407→                      <input type="checkbox" defaultChecked={pref.default} className="sr-only peer" />
408→                      <div className="w-11 h-6 bg-gray-700 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-purple-500"></div>
409→                    </label>
410→                  </div>
411→                ))}
412→              </div>
413→            </div>
414→
415→            {/* Danger Zone */}
416→            <div className="border border-red-500/20 rounded-2xl p-6 bg-red-500/5">
417→              <h3 className="text-sm font-bold text-red-400 flex items-center gap-2 mb-2">
418→                <AlertTriangle size={16} /> Zone de danger
419→              </h3>
420→              <p className="text-xs text-gray-500 mb-4">La suppression du compte est irréversible. Toutes vos données seront perdues.</p>
421→              <button className="text-xs font-bold text-red-500 hover:text-red-400 border border-red-500/30 hover:bg-red-500/10 px-4 py-2 rounded-full transition-colors">
422→                Supprimer mon compte
423→              </button>
424→            </div>
425→          </div>
426→        </div>
427→      )}
428→
429→      {/* ═══════════════════════════════════════════════
430→          TAB 2 : ABONNEMENT & PROJETS
431→          ═══════════════════════════════════════════════ */}
432→      {activeTab === 'subscription' && (
433→        <div className="animate-in fade-in duration-300 space-y-8">
