 37→        <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="8" fill="none"
 38→          strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
 39→          style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
