546→          <p className="text-2xl font-bold text-white">{stats.errorRate}%</p>
547→          <p className="text-xs text-gray-600 mt-1">Erreurs / total requetes</p>
548→        </div>
549→        <div className="ninja-card p-5">
550→          <div className="flex items-center gap-2 mb-2">
551→            <Clock size={16} className="text-blue-400" />
552→            <span className="text-xs text-gray-500 uppercase tracking-wider">Latence moyenne</span>
553→          </div>
554→          <p className="text-2xl font-bold text-white">{stats.avgLatency} ms</p>
555→          <p className="text-xs text-gray-600 mt-1">Temps de reponse moyen</p>
556→        </div>
557→      </div>
558→
559→      {/* Chart */}
560→      <div className="ninja-card p-5">
561→        <h3 className="text-sm font-semibold text-white mb-4">Requetes API - 30 derniers jours</h3>
562→        <div className="h-72">
563→          <ResponsiveContainer width="100%" height="100%">
564→            <BarChart data={usageData} barGap={0}>
565→              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
566→              <XAxis
567→                dataKey="date"
568→                tick={{ fill: '#6b7280', fontSize: 10 }}
569→                tickFormatter={(v: string) => v.slice(5)}
570→                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
571→              />
572→              <YAxis
573→                tick={{ fill: '#6b7280', fontSize: 10 }}
574→                axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
575→              />
576→              <Tooltip
577→                contentStyle={{
578→                  background: '#1a1a1a',
579→                  border: '1px solid rgba(255,255,255,0.08)',
580→                  borderRadius: '8px',
581→                  fontSize: '12px',
582→                }}
583→                labelStyle={{ color: '#9ca3af' }}
584→              />
585→              <Legend
586→                wrapperStyle={{ fontSize: '12px', color: '#9ca3af' }}
587→              />
588→              <Bar dataKey="success" stackId="a" fill="#10b981" name="Succes" radius={[0, 0, 0, 0]} />
589→              <Bar dataKey="errors" stackId="a" fill="#ef4444" name="Erreurs" radius={[2, 2, 0, 0]} />
590→            </BarChart>
591→          </ResponsiveContainer>
592→        </div>
593→      </div>
594→
595→      {/* SDK section */}
596→      <div>
597→        <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">SDK officiels</h3>
598→        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
599→          <div className="ninja-card p-5">
600→            <div className="flex items-center gap-2 mb-3">
601→              <Code2 size={16} className="text-amber-400" />
602→              <span className="text-sm font-semibold text-white">Node.js / JavaScript</span>
603→            </div>
604→            <div className="relative">
605→              <pre className="bg-black/50 border border-white/[0.06] rounded-lg p-3 text-xs font-mono text-gray-300">
606→                npm install @citedby/sdk
607→              </pre>
608→              <button
609→                onClick={() => copyToClipboard('npm install @citedby/sdk', 'sdk_npm')}
610→                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
611→              >
612→                {copiedId === 'sdk_npm' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
613→              </button>
614→            </div>
615→          </div>
616→          <div className="ninja-card p-5">
617→            <div className="flex items-center gap-2 mb-3">
618→              <Terminal size={16} className="text-blue-400" />
619→              <span className="text-sm font-semibold text-white">Python</span>
620→            </div>
621→            <div className="relative">
622→              <pre className="bg-black/50 border border-white/[0.06] rounded-lg p-3 text-xs font-mono text-gray-300">
623→                pip install citedby
624→              </pre>
625→              <button
626→                onClick={() => copyToClipboard('pip install citedby', 'sdk_pip')}
627→                className="absolute top-2 right-2 text-gray-500 hover:text-gray-300 transition-colors"
628→              >
629→                {copiedId === 'sdk_pip' ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
630→              </button>
631→            </div>
632→          </div>
633→        </div>
634→      </div>
635→    </div>
636→  );
637→
638→  // ── Main render ──
639→
640→  return (
641→    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
642→      {/* Header */}
643→      <div className="flex items-center gap-4 mb-8">
644→        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
645→          <ArrowLeft size={20} className="text-gray-400" />
646→        </button>
647→        <div className="flex-1">
648→          <div className="flex items-center gap-3">
649→            <h1 className="text-2xl font-bold text-white">
650→              <span className="gradient-text">API</span> Developer Hub
651→            </h1>
652→            <span className="bg-purple-500/10 text-purple-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-purple-500/20">
653→              BETA
654→            </span>
655→          </div>
656→          <p className="text-sm text-gray-500 mt-1">
657→            Integrez CitedBy.ai dans vos applications via notre API REST.
658→          </p>
659→        </div>
660→      </div>
661→
662→      {/* Tab bar */}
663→      <div className="flex gap-1 mb-6 border-b border-white/[0.06] overflow-x-auto">
664→        {TABS.map((tab) => {
665→          const Icon = tab.icon;
666→          const isActive = activeTab === tab.id;
667→          return (
668→            <button
669→              key={tab.id}
670→              onClick={() => setActiveTab(tab.id)}
671→              className={`flex items-center gap-2 px-4 py-3 text-sm font-medium whitespace-nowrap transition-colors border-b-2 ${
672→                isActive
673→                  ? 'text-purple-400 border-purple-500'
674→                  : 'text-gray-500 border-transparent hover:text-gray-300 hover:border-white/[0.1]'
675→              }`}
676→            >
677→              <Icon size={16} />
678→              {tab.label}
679→            </button>
680→          );
681→        })}
682→      </div>
683→
684→      {/* Tab content */}
685→      {activeTab === 'docs' && renderDocs()}
686→      {activeTab === 'keys' && renderKeys()}
687→      {activeTab === 'webhooks' && renderWebhooks()}
688→      {activeTab === 'usage' && renderUsage()}
689→    </div>
690→  );
691→};
692→
693→export default ApiDeveloper;
